

const DEFAULT_FILL = '#2D127E'

function getBaseName(pathId) {
  const parts = pathId.split('_')
  const last = parts[parts.length - 1]
  return !isNaN(parseInt(last)) ? parts.slice(0, -1).join('_') : pathId
}

function getBiomeFill(pathId, biomeColors, hoveredBiome) {
  if (!hoveredBiome) return DEFAULT_FILL
  const base = getBaseName(pathId)
  return base === hoveredBiome ? (biomeColors[base] || '#ffffff') : DEFAULT_FILL
}

